/**
 * @event 
 * @name udc_cvsslMgnt_onclickEvent 
 * @description 본선명) 검색 버튼 클릭 시 발생
 * @asis for=ed_cvsslMgntNo event=OnKillFocus()
 */
scwin.udc_cvsslMgnt_onblurCodeEvent = function (e) {

